        form = ComplexForm({"field1": "bad", "field2": "bad"})
        self.assertFalse(form.is_valid())
        self.assertIn("field1", form.errors)
        self.assertIn("field2", form.errors)

        # Only one field invalid
        form = ComplexForm({"field1": "bad", "field2": "good"})
        self.assertFalse(form.is_valid())
        self.assertIn("field1", form.errors)
        self.assertNotIn("field2", form.errors)

    def test_validator_with_optional_fields(self):
        """Test that validators handle optional fields correctly."""

        def validate_dates(cleaned_data):
            start = cleaned_data.get("start_date")
            end = cleaned_data.get("end_date")
            # Only validate if both are present
            if start and end and end <= start:
                raise ValidationError("End date must be after start date.")

        class OptionalDateForm(forms.Form):
            start_date = forms.DateField(required=False)
            end_date = forms.DateField(required=False)
            composite_validators = [
                CompositeFieldValidator(validate_dates, ["start_date", "end_date"])
            ]

        # Both empty - should be valid
        form = OptionalDateForm({})
        self.assertTrue(form.is_valid())

        # Only one field - should be valid
        form = OptionalDateForm({"start_date": "2024-01-01"})
        self.assertTrue(form.is_valid())

        # Both fields valid - should be valid
        form = OptionalDateForm(
            {"start_date": "2024-01-01", "end_date": "2024-01-02"}
        )
        self.assertTrue(form.is_valid())

        # Both fields invalid - should fail validation
        form = OptionalDateForm(
            {"start_date": "2024-01-02", "end_date": "2024-01-01"}
        )
        self.assertFalse(form.is_valid())

    def test_custom_clean_method_and_composite_validators(self):
        """Test that both custom clean() and composite validators work together."""

        def composite_validate(cleaned_data):
            if cleaned_data.get("field1") == "composite_bad":
                raise ValidationError("Composite validation failed.")

        class CustomForm(forms.Form):
            field1 = forms.CharField()
            field2 = forms.CharField()
            composite_validators = [
                CompositeFieldValidator(composite_validate, ["field1"])
            ]

            def clean(self):
                cleaned_data = super().clean()
                if cleaned_data.get("field2") == "clean_bad":
                    raise ValidationError("Custom clean validation failed.")
                return cleaned_data

        # Both valid
        form = CustomForm({"field1": "good", "field2": "good"})
        self.assertTrue(form.is_valid())

        # Custom clean fails
        form = CustomForm({"field1": "good", "field2": "clean_bad"})
        self.assertFalse(form.is_valid())

        # Composite validation fails
        form = CustomForm({"field1": "composite_bad", "field2": "good"})
        self.assertFalse(form.is_valid())

        # Both fail
        form = CustomForm({"field1": "composite_bad", "field2": "clean_bad"})
        self.assertFalse(form.is_valid())

